//Generate a random STRING containing alphanumeric characters
//Parameter - The desired character length of the string as an integer e.g. generateRandomString(10);
function generateRandomString(length) {
	var string = "";
	var chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";

	for (var i = 0; i < length; i++) {
		string += chars.charAt(Math.floor(Math.random() * chars.length));
	}

	return string;
}


/*
 * Method used to replace a specific character in a string by index
 */
function replaceAt(instr, index, replacement) {
    return instr.substr(0, index) + replacement+ instr.substr(index + replacement.length);
}


//Helper function to allow show hide element based on two variables.
//usage: toggleInfo('#show-info-btn', '#info-element');
function toggleInfo(btn, info) {
	const triggerElement = document.querySelector(btn);
	const targetElement = document.querySelector(info);

	if (!triggerElement || !targetElement) {
		console.error('Invalid selector!');
		return;
	}

	triggerElement.addEventListener('click', () => {
		targetElement.style.display = targetElement.style.display === 'none' ? 'block' : 'none';
	});
}

