}

function checkValidatorFields () {
	/* declare and find error messages associated with each input */
	var element;
	var elements = $(".help-block");

	/*
		- Loop through each error type. Filter if they are valid/not validated or invalid (else)
		- Grab error message and find closest input
		- Make title = error message (screen reader friendly)
		- if valid, remove title

	*/
	for (var i = 0; i < elements.length; i++) {
		element=elements.eq(i);

		elementValid = element.attr("data-fv-result") == 'VALID';
		elementNotValidated = element.attr("data-fv-result") == 'NOT_VALIDATED';
		elementInvalid = element.attr("data-fv-result") == 'INVALID';

		/* Get parent element. Find child label to insert error later */
		closestLabel = $(element).parent(".form-group").find('.control-label');

		if (elementValid) {
			element.attr("hidden","");
		}
		if (elementNotValidated) {
			element.removeAttr("hidden");
		}
		if (elementInvalid) {
			element.removeAttr("hidden");
		}
		closestLabel.append( $(element));

	}
}

/* When called, will focus on first input with error) */
function findFirstError() {
	// Check for previously added "has-error-first" and remove
	var hasSuccess = $(".has-success");
	for (var i = 0; i < hasSuccess.length; i++) {
		hasSuccessItem=hasSuccess.eq(i);
		if(hasSuccessItem.hasClass("has-error-first")) {
			hasSuccessItem.removeClass("has-error-first");
		}
	}
	$(".has-error-first").removeClass("has-error-first");
	$(".has-error").first().addClass("has-error-first");
}

function scrollToError() {
	var firstError = $(".has-error-first");
	if(firstError) {
		$('html,body').animate({scrollTop: firstError.offset().top - 100});
	}
	firstError.find(".control-label").focus();
}

/* Function to add onclick event to submit/next buttons */
function addOnclick () {

	var button;
	var buttons = document.getElementsByClassName("btn");
	for (var i = 0; i < buttons.length; i++) {
		button=buttons.item(i);
		if(button.getAttribute("value") !=null) {
			var buttonValue = button.getAttribute("value").toLowerCase().replace(/\s/g,'');
			//When adding a new button value remove all spaces/make lower case
			switch(buttonValue) {
				case 'next':
				case 'paynow':
				case 'submit':
				case 'adduser':
					button.addEventListener("click", function() {
					onButtonClick();
				})
			    break;
				default:
			    console.log(button.getAttribute("value"));
			}
		}
	}
}

