/**
 * Author: 			Ethan Bristow
 * Contributors:	
 * Title:			text_counter.js
 * Description:		Contains JS functions to limit the text count of an input/text area field and output the length in the HTML of another element (Usually span).
 * Notes:			Should be after jQuery and before app specific JS.
 * Version: 		0.0.1
 */

/**
 * Vanilla JS version ~2013 Steve Butts
 * @param 'limitfield' The ID of the input/text area field to be limited.
 * @param 'counter' The ID of the element to output the current character count.
 * @param 'maxlimit' The max number of characters allowed.
 */
function limitText(limitfield,counter,maxlimit) {
	
	if (document.getElementById(limitfield).value.length > maxlimit) {
		document.getElementById(limitfield).value = document.getElementById(limitfield).value.substring(0, maxlimit);
	}else{
		document.getElementById(counter).innerHTML = maxlimit - document.getElementById(limitfield).value.length;
	}
}

/**
 * jQuery version
 * @param 'limitfield' The ID of the input/text area field to be limited.
 * @param 'counter' The ID of the element to output the current character count.
 * @param 'maxlimit' The max number of characters allowed.
 */
function newLimitText(limitfield, counter, maxlimit) {
	
	var length = $('#' + limitfield).val().length;
	length = parseInt(length, 10);
	maxlimit = parseInt(maxlimit, 10);

	if (length > maxlimit) {
		$('#' + limitfield).val( $('#' + limitfield).val().substring(0, maxlimit) );
	} else {
		$('#' + counter).html(maxlimit - length); 
	}
	
}

