	if(sAuth.toUpperCase()=="WCC"||sAuth==3) return "3";
	if(sAuth.toUpperCase()=="MHDC"||sAuth==2) return "2";
	if(sAuth.toUpperCase()=="WDC"||sAuth==1) return "1";
	if(sAuth.toUpperCase()=="BDC"||sAuth==5) return "5";
	if(sAuth.toUpperCase()=="RBC"||sAuth==4) return "4";
	if(sAuth.toUpperCase()=="WFDC"||sAuth==6) return "6";
	if(sAuth.toUpperCase()=="WCTYC"||sAuth==7) return "7";
	if(sAuth.toUpperCase()=="SW2"||sAuth==8) return "8";	
	if(sAuth.toUpperCase()=="SWBC"||sAuth==9) return "9";
	if(sAuth.toUpperCase()=="WCCALL"||sAuth==10) return "10";
}


//RG 050813
function GetAuthString(sAuth){
	if(sAuth.toUpperCase()=="WCC"||sAuth==3) return "WCC";
	if(sAuth.toUpperCase()=="MHDC"||sAuth==2) return "MHDC";
	if(sAuth.toUpperCase()=="WDC"||sAuth==1) return "WDC";
	if(sAuth.toUpperCase()=="BDC"||sAuth==5) return "BDC";
	if(sAuth.toUpperCase()=="RBC"||sAuth==4) return "RBC";
	if(sAuth.toUpperCase()=="WFDC"||sAuth==6) return "WFDC";
	if(sAuth.toUpperCase()=="WCTYC"||sAuth==7) return "WCTYC";
	if(sAuth.toUpperCase()=="SW2"||sAuth==8) return "SW2";	
	if(sAuth.toUpperCase()=="SWBC"||sAuth==9) return "SWBC";
	if(sAuth.toUpperCase()=="WCCALL"||sAuth==10) return "WCCALL";
}

